246. 	 */
247. 	setWorkspacePath(path: string | null): void {
248. 		const message: WorkspacePathPayload = {
249. 			type: 'workspacePath',
250. 			path
251. 		};
252. 		this.send(message);
253. 	}
254. 	
255. 	/**
256. 	 * Active file changed
257. 	 */
258. 	setActiveFile(filePath: string | null): void {
259. 		const message: ActiveFileChangedPayload = {
260. 			type: 'activeFileChanged',
261. 			filePath
262. 		};
263. 		this.send(message);
