265. 	
266. 	/**
267. 	 * Send diff available data to webview
268. 	 * 
269. 	 * Forwards complete diff information including tool ID and file paths.
270. 	 * Webview uses toolCallId to locate the tool element and add diff button.
271. 	 */
272. 	sendDiffAvailable(diffData: { toolCallId: string; beforeUri: string; afterUri: string; title: string; diffLines?: Array<{ type: 'add' | 'remove' | 'context'; text: string }>; diffTruncated?: boolean; diffTotalLines?: number }): void {
273. 		const message: DiffAvailablePayload = {
274. 			type: 'diffAvailable',
275. 			toolCallId: diffData.toolCallId,
276. 			beforeUri: diffData.beforeUri,
277. 			afterUri: diffData.afterUri,
278. 			title: diffData.title,
279. 			diffLines: diffData.diffLines,
280. 			diffTruncated: diffData.diffTruncated,
281. 			diffTotalLines: diffData.diffTotalLines
282. 		};
283. 		this.send(message);
284. 	}
285. 	
286. 	/**
287. 	 * Append to last message
288. 	 */
289. 	appendMessage(text: string): void {
290. 		const message: AppendMessagePayload = {
291. 			type: 'appendMessage',
292. 			text
293. 		};
294. 		this.send(message);
295. 	}
296. 	
297. 	/**
298. 	 * Attachment validation result
299. 	 */
300. 	attachmentValidation(valid: boolean, error: string | null): void {
301. 		const message: AttachmentValidationPayload = {
302. 			type: 'attachmentValidation',
303. 			valid,
304. 			error
305. 		};
306. 		this.send(message);
307. 	}
