325. 			type: 'usage_info',
326. 			usage
327. 		};
328. 		this.send(message);
329. 	}
330. 
331. 	/**
332. 	 * Model switch result
333. 	 */
334. 	sendModelSwitched(model: string, success: boolean): void {
335. 		const message: ModelSwitchedPayload = {
336. 			type: 'modelSwitched',
337. 			model,
338. 			success
339. 		};
340. 		this.send(message);
341. 	}
342. 
343. 	/**
344. 	 * Current model notification
345. 	 */
346. 	sendCurrentModel(model: string): void {
347. 		const message: CurrentModelPayload = {
348. 			type: 'currentModel',
349. 			model
350. 		};
351. 		this.send(message);
352. 	}
353. 
354. 	/**
355. 	 * Send available models list to webview
356. 	 */
357. 	sendAvailableModels(models: Array<{ id: string; name: string; multiplier?: number }>): void {
358. 		const message: AvailableModelsPayload = {
359. 			type: 'availableModels',
360. 			models
361. 		};
362. 		this.send(message);
363. 	}
364. 
365. 	// ========================================================================
366. 	// Receive Handlers (Webview → Extension)
367. 	// ========================================================================
368. 	
369. 	/**
370. 	 * Register handler for sendMessage
371. 	 */
372. 	onSendMessage(handler: MessageHandler<SendMessagePayload>): Disposable {
373. 		return this.registerHandler('sendMessage', handler);
374. 	}
375. 	
376. 	/**
377. 	 * Register handler for abortMessage
378. 	 */
379. 	onAbortMessage(handler: MessageHandler<AbortMessagePayload>): Disposable {
380. 		return this.registerHandler('abortMessage', handler);
381. 	}
382. 	
383. 	/**
384. 	 * Register handler for ready
385. 	 */
386. 	onReady(handler: MessageHandler<ReadyPayload>): Disposable {
387. 		return this.registerHandler('ready', handler);
388. 	}
389. 	
390. 	/**
391. 	 * Register handler for switchSession
392. 	 */
393. 	onSwitchSession(handler: MessageHandler<SwitchSessionPayload>): Disposable {
394. 		return this.registerHandler('switchSession', handler);
395. 	}
396. 	
397. 	/**
398. 	 * Register handler for newSession
399. 	 */
400. 	onNewSession(handler: MessageHandler<NewSessionPayload>): Disposable {
401. 		return this.registerHandler('newSession', handler);
402. 	}
403. 	
404. 	/**
405. 	 * Register handler for viewPlan
406. 	 */
407. 	onViewPlan(handler: MessageHandler<ViewPlanPayload>): Disposable {
408. 		return this.registerHandler('viewPlan', handler);
409. 	}
410. 	
411. 	/**
412. 	 * Register handler for viewDiff
413. 	 */
414. 	onViewDiff(handler: MessageHandler<ViewDiffPayload>): Disposable {
415. 		return this.registerHandler('viewDiff', handler);
416. 	}
417. 	
418. 	/**
419. 	 * Register handler for togglePlanMode
420. 	 */
421. 	onTogglePlanMode(handler: MessageHandler<TogglePlanModePayload>): Disposable {
422. 		return this.registerHandler('togglePlanMode', handler);
423. 	}
424. 	
425. 	/**
426. 	 * Register handler for acceptPlan
427. 	 */
428. 	onAcceptPlan(handler: MessageHandler<AcceptPlanPayload>): Disposable {
429. 		return this.registerHandler('acceptPlan', handler);
430. 	}
431. 	
432. 	/**
433. 	 * Register handler for rejectPlan
434. 	 */
435. 	onRejectPlan(handler: MessageHandler<RejectPlanPayload>): Disposable {
436. 		return this.registerHandler('rejectPlan', handler);
437. 	}
438. 	
439. 	/**
440. 	 * Register handler for pickFiles
441. 	 */
442. 	onPickFiles(handler: MessageHandler<PickFilesPayload>): Disposable {
443. 		return this.registerHandler('pickFiles', handler);
444. 	}
445. 	
446. 	/**
447. 	 * Register handler for pasteImage
448. 	 */
449. 	onPasteImage(handler: MessageHandler<PasteImagePayload>): Disposable {
450. 		return this.registerHandler('pasteImage', handler);
451. 	}
452. 
453. 	/**
454. 	 * Register handler for saveMermaidImage
455. 	 */
456. 	onSaveMermaidImage(handler: MessageHandler<SaveMermaidImagePayload>): Disposable {
457. 		return this.registerHandler('saveMermaidImage', handler);
458. 	}
459. 
460. 	/**
461. 	 * Register handler for showPlanContent
462. 	 */
463. 	onShowPlanContent(handler: MessageHandler<ShowPlanContentPayload>): Disposable {
464. 		return this.registerHandler('showPlanContent', handler);
465. 	}
466. 	
467. 	/**
468. 	 * Register handler for openDiffView
469. 	 */
470. 	onOpenDiffView(handler: MessageHandler<OpenDiffViewPayload>): Disposable {
471. 		return this.registerHandler('openDiffView', handler);
472. 	}
473. 	
474. 	/**
475. 	 * Register handler for showMcpConfig
476. 	 */
477. 	onShowMcpConfig(handler: MessageHandler<ShowMcpConfigPayload>): Disposable {
478. 		return this.registerHandler('showMcpConfig', handler);
479. 	}
480. 	
481. 	/**
482. 	 * Register handler for showUsageMetrics
483. 	 */
484. 	onShowUsageMetrics(handler: MessageHandler<ShowUsageMetricsPayload>): Disposable {
485. 		return this.registerHandler('showUsageMetrics', handler);
486. 	}
487. 	
488. 	/**
489. 	 * Register handler for showHelp
490. 	 */
491. 	onShowHelp(handler: MessageHandler<ShowHelpPayload>): Disposable {
492. 		return this.registerHandler('showHelp', handler);
493. 	}
494. 	
495. 	/**
496. 	 * Register handler for showNotSupported
497. 	 */
498. 	onShowNotSupported(handler: MessageHandler<ShowNotSupportedPayload>): Disposable {
499. 		return this.registerHandler('showNotSupported', handler);
500. 	}
501. 	
502. 	/**
503. 	 * Register handler for openInCLI
504. 	 */
505. 	onOpenInCLI(handler: MessageHandler<OpenInCLIPayload>): Disposable {
506. 		return this.registerHandler('openInCLI', handler);
507. 	}
508. 
509. 	/**
510. 	 * Register handler for enableFleetMode
511. 	 */
512. 	onEnableFleetMode(handler: MessageHandler<EnableFleetModePayload>): Disposable {
513. 		return this.registerHandler('enableFleetMode', handler);
514. 	}
515. 
516. 	/**
517. 	 * Register handler for openFile
518. 	 */
519. 	onOpenFile(handler: MessageHandler<OpenFilePayload>): Disposable {
520. 		return this.registerHandler('openFile', handler);
521. 	}
522. 
523. 	/**
524. 	 * Register handler for switchModel
525. 	 */
526. 	onSwitchModel(handler: MessageHandler<SwitchModelPayload>): Disposable {
527. 		return this.registerHandler('switchModel', handler);
528. 	}
529. 
530. 	/**
531. 	 * Register handler for renameSession
532. 	 */
533. 	onRenameSession(handler: MessageHandler<RenameSessionPayload>): Disposable {
534. 		return this.registerHandler('renameSession', handler);
535. 	}
536. 
537. 	// ========================================================================
538. 	// Message Routing
539. 	// ========================================================================
540. 	
541. 	/**
542. 	 * Route incoming webview message to registered handler
543. 	 */
544. 	route(message: WebviewMessage): void {
545. 		// Track incoming messages
546. 		this.incomingMessageCount++;
547. 		this.trackMessageType(`IN:${message.type}`);
548. 		
549. 		// Report periodically
550. 		if (this.incomingMessageCount % this.REPORT_INTERVAL === 0) {
551. 			this.reportMessageStats('INCOMING');
552. 		}
553. 		
554. 		const handler = this.handlers.get(message.type as WebviewMessageType);
555. 		
556. 		if (handler) {
557. 			try {
558. 				handler(message);
559. 			} catch (error) {
560. 				console.error(`Error in handler for ${message.type}:`, error);
561. 			}
562. 		} else {
563. 			console.warn(`No handler registered for message type: ${message.type}`);
564. 		}
565. 	}
566. 	
567. 	/**
568. 	 * Set up webview message listener
569. 	 * Call this once to start routing messages
570. 	 */
571. 	listen(): Disposable {
572. 		return this.webview.onDidReceiveMessage((message: WebviewMessage) => {
573. 			this.route(message);
574. 		});
575. 	}
576. 	
577. 	// ========================================================================
578. 	// Private Methods
579. 	// ========================================================================
580. 	
581. 	/**
582. 	 * Send message to webview
583. 	 */
584. 	private send(message: ExtensionMessage): void {
585. 		// Track outgoing messages
586. 		this.outgoingMessageCount++;
587. 		this.trackMessageType(`OUT:${message.type}`);
588. 		
589. 		// Report periodically
590. 		if (this.outgoingMessageCount % this.REPORT_INTERVAL === 0) {
591. 			this.reportMessageStats('OUTGOING');
592. 		}
593. 		
594. 		this.webview.postMessage(message);
595. 	}
596. 	
597. 	/**
598. 	 * Register a message handler
599. 	 */
600. 	private registerHandler<T extends WebviewMessage>(
601. 		type: WebviewMessageType,
602. 		handler: MessageHandler<T>
603. 	): Disposable {
604. 		// Only allow one handler per type (last one wins)
605. 		this.handlers.set(type, handler as MessageHandler<any>);
606. 		
607. 		return {
608. 			dispose: () => {
609. 				if (this.handlers.get(type) === handler) {
610. 					this.handlers.delete(type);
611. 				}
612. 			}
613. 		};
614. 	}
615. 	
616. 	/**
617. 	 * Track message type count
618. 	 */
619. 	private trackMessageType(type: string): void {
620. 		const count = this.messageCountByType.get(type) || 0;
621. 		this.messageCountByType.set(type, count + 1);
622. 	}
623. 	
624. 	/**
625. 	 * Report message statistics
626. 	 */
627. 	private reportMessageStats(direction: 'INCOMING' | 'OUTGOING'): void {
628. 		const now = Date.now();
629. 		const timeSinceLastReport = now - this.lastReportedAt;
630. 		
631. 		console.log('='.repeat(80));
632. 		console.log(`[MESSAGE DEBUG] ${direction} Message Stats`);
633. 		console.log(`Total incoming: ${this.incomingMessageCount}`);
634. 		console.log(`Total outgoing: ${this.outgoingMessageCount}`);
635. 		console.log(`Time since last report: ${timeSinceLastReport}ms`);
636. 		console.log('Breakdown by type:');
637. 		
638. 		// Sort by count descending
639. 		const sortedTypes = Array.from(this.messageCountByType.entries())
640. 			.sort((a, b) => b[1] - a[1]);
641. 		
642. 		for (const [type, count] of sortedTypes) {
643. 			console.log(`  ${type}: ${count}`);
644. 		}
645. 		
646. 		console.log('='.repeat(80));
647. 		this.lastReportedAt = now;
648. 	}
649. 	
650. 	/**
651. 	 * Get current message statistics (useful for manual inspection)
652. 	 */
653. 	public getMessageStats(): { incoming: number; outgoing: number; byType: Map<string, number> } {
654. 		return {
655. 			incoming: this.incomingMessageCount,
656. 			outgoing: this.outgoingMessageCount,
657. 			byType: new Map(this.messageCountByType)
658. 		};
659. 	}
660. }
